# Run a cross-tenant inventory report
$tenants = @(
    @{Tenant="contoso.onmicrosoft.com"; AppId="<app-id>"; Secret="<secret>"},
    @{Tenant="fabrikam.onmicrosoft.com"; AppId="<app-id>"; Secret="<secret>"}
)

$report = foreach ($t in $tenants) {
    $cred = [PSCredential]::new($t.AppId, (ConvertTo-SecureString $t.Secret -AsPlainText -Force))
    Connect-AzAccount -ServicePrincipal -Tenant $t.Tenant -Credential $cred | Out-Null

    Get-AzSubscription | ForEach-Object {
        Set-AzContext -SubscriptionId $_.Id | Out-Null
        $vms = Get-AzVM
        [PSCustomObject]@{
            Tenant       = $t.Tenant
            Subscription = $_.Name
            VMCount      = $vms.Count
            Locations    = ($vms | Select-Object -ExpandProperty Location -Unique) -join ", "
        }
    }
}

$report | Format-Table -AutoSize
